class Solution:
    def countSubmatrices(self, grid, k):
        m, n = len(grid), len(grid[0])
        count = 0
        for r in range(m):
            for c in range(n):
                total = sum(grid[i][j] for i in range(r+1) for j in range(c+1))
                if total <= k:
                    count += 1
        return count

