class Solution:
    def countSubmatrices(self, grid, k):
        m, n = len(grid), len(grid[0])
        prefix = [[0] * (n + 1) for _ in range(m + 1)]
        count = 0
        for r in range(m):
            for c in range(n):
                prefix[r+1][c+1] = grid[r][c] + prefix[r][c+1] + prefix[r+1][c] - prefix[r][c]
                if prefix[r+1][c+1] <= k:
                    count += 1
        return count

