var countSubmatrices = function(grid, k) {
    const m = grid.length, n = grid[0].length;
    const prefix = Array.from({length: m+1}, () => new Array(n+1).fill(0));
    let count = 0;
    for (let r = 0; r < m; r++) {
        for (let c = 0; c < n; c++) {
            prefix[r+1][c+1] = grid[r][c] + prefix[r][c+1] + prefix[r+1][c] - prefix[r][c];
            if (prefix[r+1][c+1] <= k) count++;
        }
    }
    return count;
};
